import{p as n,bh as i,I as a,U as e}from"./chunks/framework.BpabEsSf.js";const s=JSON.parse('{"title":"Documentation Map","description":"","frontmatter":{"title":"Documentation Map","date":"2025-05-01T23:00:00.000Z","permalink":"/reference/catalogue"},"headers":[],"relativePath":"vi/02.Configuration/01.Documentation Map.md","filePath":"vi/02.Configuration/01.Documentation Map.md","lastUpdated":null}'),h={name:"vi/02.Configuration/01.Documentation Map.md"};function c(o,t,r,u,d,l){return i(),a("div",null,[...t[0]||(t[0]=[e('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\02.Configuration\\01.Documentation Map.md for this page in Markdown format</div><h1 id="🗺️-ban-đo-đieu-huong-tai-lieu-toan-cuc-monica" tabindex="-1">🗺️ Bản đồ điều hướng tài liệu toàn cục Monica <a class="header-anchor" href="#🗺️-ban-đo-đieu-huong-tai-lieu-toan-cuc-monica" aria-label="Permalink to &quot;🗺️ Bản đồ điều hướng tài liệu toàn cục Monica&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Tóm tắt</p><p>Chào mừng bạn đến với trung tâm tài liệu chính thức của hệ sinh thái kho lưu trữ cục bộ <code>Monica</code>. Sơ đồ ma trận này đóng vai trò là điểm truy cập nhanh của bạn đến các hướng dẫn sử dụng cốt lõi, khung kiến trúc và thông số kỹ thuật phát triển của phần mềm chúng tôi.</p></div><h2 id="🚀-01-nhap-mon-huong-dan-guide" tabindex="-1">🚀 01. Nhập môn &amp; Hướng dẫn (Guide) <a class="header-anchor" href="#🚀-01-nhap-mon-huong-dan-guide" aria-label="Permalink to &quot;🚀 01. Nhập môn &amp; Hướng dẫn (Guide)&quot;">​</a></h2><p>Chương này chứa các nội dung tổng quan cơ bản về dự án, triết lý thiết kế toàn cục và các hướng dẫn vận hành hàng ngày được điều chỉnh riêng cho người dùng cuối.</p><ul><li><strong><a href="/vi/guide/intro.html">📖 Giới thiệu dự án</a></strong> * <em>Một kho lưu trữ ưu tiên cục bộ tích hợp hệ sinh thái Bitwarden và KeePass. Toàn cảnh các tính năng nổi bật, triết lý nguồn mở và thông báo tài sản.</em></li><li><strong><a href="/vi/guide/overview.html">🎯 Tổng quan giao diện</a></strong> * <em>Nhanh chóng nắm bắt ranh giới khả năng cốt lõi và bố cục khung giao diện (UI) của ứng dụng khách (client) và các tiện ích mở rộng trình duyệt.</em></li><li><strong><a href="/vi/guide/quickstart.html">📝 Khởi động nhanh</a></strong> * <em>Bắt đầu từ số không và đưa Monica vào vận hành ngay lập tức.</em></li></ul><h2 id="🛠️-02-nha-phat-trien-thong-so-ky-thuat-developer-specifications" tabindex="-1">🛠️ 02. Nhà phát triển &amp; Thông số kỹ thuật (Developer Specifications) <a class="header-anchor" href="#🛠️-02-nha-phat-trien-thong-so-ky-thuat-developer-specifications" aria-label="Permalink to &quot;🛠️ 02. Nhà phát triển &amp; Thông số kỹ thuật (Developer Specifications)&quot;">​</a></h2><p>Được thiết kế đặc biệt dành cho các nhà đóng góp nguồn mở, nhà phát triển thứ cấp và những người dùng nâng cao muốn kiểm toán cấu trúc bảo mật dữ liệu riêng tư.</p><ul><li><strong><a href="/vi/reference/webdav-backup-specification.html">📦 Thông số định dạng sao lưu WebDAV</a></strong> * <em>Giải mã dòng luồng đồng bộ hóa xuyên thiết bị! Giải thích về cấu trúc lưu trữ của tệp <code>.zip</code> tiêu chuẩn và tệp mã hóa nhị phân <code>.enc.zip</code>, các trường dữ liệu JSON schema, luồng mã hóa AES-256-GCM và logic khôi phục dự phòng cấp dòng.</em></li><li><strong><a href="/vi/reference/android-storage-security.html">🔄 Tài liệu kỹ thuật lưu trữ cục bộ &amp; Mã hóa</a></strong> * <em>Phân tích triển khai kỹ thuật bao gồm kiểm soát sandbox lưu trữ cục bộ và các sơ đồ mã hóa cấp thấp.</em></li></ul><h2 id="📈-trang-thai-tien-hoa-du-an" tabindex="-1">📈 Trạng thái tiến hóa dự án <a class="header-anchor" href="#📈-trang-thai-tien-hoa-du-an" aria-label="Permalink to &quot;📈 Trạng thái tiến hóa dự án&quot;">​</a></h2><div class="center tk-center-container"><table tabindex="0"><thead><tr><th style="text-align:center;">Phiên bản cốt lõi hiện tại</th><th style="text-align:center;">Yêu cầu nền tảng mục tiêu</th><th style="text-align:center;">Loại giấy phép nguồn mở</th></tr></thead><tbody><tr><td style="text-align:center;"><code>v1.4.0</code></td><td style="text-align:center;">Android 8.0+ / Web</td><td style="text-align:center;"><a href="./LICENSE.html">GNU GPL v3.0</a></td></tr></tbody></table></div>',11)])])}const m=n(h,[["render",c]]);export{s as __pageData,m as default};
